mapper.select:
SELECT fr.id, fr.borrow_id, fr.user_id, fr.book_id, fr.overdue_days, fr.fine_amount, fr.payment_status, fr.create_time, fr.update_time, fr.is_deleted, u.username, u.real_name, u.student_no, b.title AS book_title, b.isbn FROM fine_record fr LEFT JOIN sys_user u ON fr.user_id = u.id AND u.is_deleted = 0 LEFT JOIN book_info b ON fr.book_id = b.id AND b.is_deleted = 0 WHERE fr.is_deleted = 0
AND fr.user_id = #{userId}
AND (u.username LIKE CONCAT('%', #{username}, '%') OR u.real_name LIKE CONCAT('%', #{username}, '%'))
AND fr.payment_status = #{paymentStatus}
ORDER BY fr.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM fine_record fr LEFT JOIN sys_user u ON fr.user_id = u.id AND u.is_deleted = 0 WHERE fr.is_deleted = 0
AND fr.user_id = #{userId}
AND (u.username LIKE CONCAT('%', #{username}, '%') OR u.real_name LIKE CONCAT('%', #{username}, '%'))
AND fr.payment_status = #{paymentStatus}
